+    expect(relativeEntropy(p, q)).toBeCloseTo(relativeEntropy(q, p), 5);
+  });
+
+  it('returns positive value for different distributions', () => {
+    const p = [0.9, 0.1];
+    const q = [0.5, 0.5];
+    expect(relativeEntropy(p, q)).toBeGreaterThan(0);
+  });
+});
